CREATE DATABASE IF NOT EXISTS RF_User;
USE RF_User;
CREATE TABLE nopach( IP VARCHAR(255) NULL );
CREATE TABLE tbl_block_ip( nSerial INT AUTO_INCREMENT NOT NULL, addr0 TINYINT NOT NULL, addr1 TINYINT NOT NULL, addr2 TINYINT NOT NULL, addr3 TINYINT NOT NULL, addr4 TINYINT NOT NULL, addr2range TINYINT NOT NULL, CONSTRAINT PK_tbl_block_ip PRIMARY KEY ( nSerial ASC ) );
CREATE TABLE tbl_bugtime_connect_in_pcbang( nworldcode INT NOT NULL, navatorserial INT NULL, account CHAR(17) NULL );
CREATE TABLE tbl_bugtime_connectpcbang( f1 TINYINT NOT NULL, f2 TINYINT NOT NULL, f3 TINYINT NOT NULL, f4 TINYINT NOT NULL );
CREATE TABLE tbl_chargeresultstr( ID TINYINT NOT NULL, strError VARCHAR(32) NOT NULL, CONSTRAINT PK_tbl_chargeresultstr PRIMARY KEY ( ID ASC ) );
CREATE TABLE tbl_connect_in_bugtime( ip VARCHAR(16) NOT NULL );
CREATE TABLE tbl_connect_pcbang( ip VARCHAR(16) NOT NULL );
CREATE TABLE tbl_connectpcbang_charserial( nWorldCode TINYINT NOT NULL, nAvatorSerial INT NOT NULL );
CREATE TABLE tbl_CristalBattle_Log( ID INT AUTO_INCREMENT NOT NULL, DID INT NOT NULL, SID INT NOT NULL, Nth TINYINT NOT NULL, MasterRace TINYINT NOT NULL, MasterName VARCHAR(17) NOT NULL, MasterClass CHAR(4) NOT NULL, B_BossName VARCHAR(17) NOT NULL, C_BossName VARCHAR(17) NOT NULL, A_BossName VARCHAR(17) NOT NULL, MasterSubBossName1 VARCHAR(17) NOT NULL, MasterSubBossName2 VARCHAR(17) NOT NULL, MasterSubBossName3 VARCHAR(17) NOT NULL, MasterSubBossName4 VARCHAR(17) NOT NULL, MasterSubBossName5 VARCHAR(17) NOT NULL, StartTime DATETIME NOT NULL, GetTime DATETIME NOT NULL, ChaosHour TINYINT NOT NULL, ChaosMin TINYINT NOT NULL, ElapseHour TINYINT NOT NULL, ElapseMin TINYINT NOT NULL, ElapseSec TINYINT NOT NULL, KeeperHitter VARCHAR(17) NOT NULL, ByAnimus TINYINT NOT NULL, DestroyRace TINYINT NULL, CONSTRAINT PK_tbl_CristalBattle_Log PRIMARY KEY ( ID ASC ) );
CREATE TABLE tbl_exp_connectip( F1 TINYINT NOT NULL, F2 TINYINT NOT NULL, F3 TINYINT NOT NULL, F4 TINYINT NOT NULL );
CREATE TABLE tbl_GMActLog( ID INT AUTO_INCREMENT NOT NULL, Account VARCHAR(17) NOT NULL, TID INT NOT NULL, PID INT NOT NULL, ActDate DATETIME NOT NULL, CONSTRAINT PK_tbl_GMActLog PRIMARY KEY ( ID ASC ) );
CREATE TABLE tbl_GMActParam( ID INT AUTO_INCREMENT NOT NULL, Param1 BLOB NULL, Param2 BLOB NULL, Param3 BLOB NULL, Param4 BLOB NULL, Param5 BLOB NULL, Param6 BLOB NULL, Param7 BLOB NULL, Param8 BLOB NULL, Param9 BLOB NULL, CONSTRAINT PK_tbl_GMActParam PRIMARY KEY ( ID ASC ) );
CREATE TABLE tbl_GMActType( ID INT NOT NULL, bLog TINYINT(1) NOT NULL, TypeName VARCHAR(50) NOT NULL, TypeNameKor VARCHAR(50) NOT NULL, CONSTRAINT PK_tbl_GMActType PRIMARY KEY ( ID ASC ) );
CREATE TABLE tbl_GMjobLog( nSerial INT AUTO_INCREMENT NOT NULL, szGMID VARCHAR(18) NOT NULL, nKind TINYINT NOT NULL, szAvatorName VARCHAR(18) NULL, nAvatorSerial INT NULL, nAccountSerial INT NULL, szDetail VARCHAR(50) NOT NULL, dtDate DATETIME NOT NULL, CONSTRAINT PK_tbl_GMjobLog PRIMARY KEY ( nSerial ASC ) );
CREATE TABLE tbl_HolyQuest_Log( serial INT AUTO_INCREMENT NOT NULL, ServerName VARCHAR(32) NOT NULL, race TINYINT NOT NULL, CharName VARCHAR(17) NOT NULL, LogDate DATETIME NOT NULL, dstRace TINYINT NOT NULL, CONSTRAINT PK_tbl_HolyQuest_Log PRIMARY KEY ( serial ASC ) );
CREATE TABLE tbl_HostAccount( Account VARCHAR(17) NOT NULL, Password VARCHAR(17) NOT NULL, Serial INT AUTO_INCREMENT NOT NULL, Grade TINYINT NOT NULL, Depart VARCHAR(24) NULL, RealName VARCHAR(12) NULL, Grade1 TINYINT NOT NULL, CONSTRAINT PK_tbl_HostAccount PRIMARY KEY ( Account ASC ) );
CREATE TABLE tbl_iplist_pcbang( IP1 TINYINT NOT NULL, IP2 TINYINT NOT NULL, IP3 TINYINT NOT NULL, IP4 TINYINT NOT NULL, lastip TINYINT NOT NULL, CONSTRAINT PK_iplist_pcbangt PRIMARY KEY ( IP1 ASC, IP2 ASC, IP3 ASC, IP4 ASC ) );
CREATE TABLE tbl_ItemBatch( ID INT AUTO_INCREMENT NOT NULL, DCK TINYINT(1) NULL, RID TINYINT NULL, account VARCHAR(17) NOT NULL, server VARCHAR(32) NOT NULL, name VARCHAR(17) NOT NULL, serial INT NOT NULL, itemcode VARCHAR(10) NOT NULL, D INT NOT NULL, U VARCHAR(15) NOT NULL, adddate DATETIME NULL, givedate DATETIME NULL, deldate DATETIME NULL, charger VARCHAR(17) NULL, deleter VARCHAR(17) NULL );
CREATE TABLE tbl_LUAccount( id VARBINARY(16) NOT NULL, password VARBINARY(24) NOT NULL, BCodeTU TINYINT NOT NULL, accounttype TINYINT NULL, Email VARCHAR(50) NULL, CONSTRAINT PK_RF_LUAccount PRIMARY KEY ( id ASC ) );
CREATE TABLE tbl_protocolaccesslog( Idx INT AUTO_INCREMENT NOT NULL, ProtocolMsgID INT NOT NULL, ProtocolID INT NOT NULL, GMSerial INT NOT NULL, AccessDate DATETIME NOT NULL, ProtocolFld0 VARBINARY(128) NULL, ProtocolFld1 VARBINARY(128) NULL, ProtocolFld2 VARBINARY(128) NULL, ProtocolFld3 VARBINARY(128) NULL, ProtocolFld4 VARBINARY(128) NULL, ProtocolFld5 VARBINARY(128) NULL, ProtocolFld6 VARBINARY(128) NULL, ProtocolFld7 VARBINARY(128) NULL, ProtocolFld8 VARBINARY(128) NULL, ProtocolFld9 VARBINARY(128) NULL, CONSTRAINT PF_tbl_protocolaccesslog_Idx PRIMARY KEY ( Idx ASC ) );
CREATE TABLE tbl_protocolauthinfo( Idx INT AUTO_INCREMENT NOT NULL, dck TINYINT(1) NOT NULL, P_MsgID INT NOT NULL, P_ID INT NOT NULL, P_AuthType TINYINT NOT NULL, GMID VARCHAR(17) NOT NULL, GMSerial INT NOT NULL, CONSTRAINT PF_tbl_protocolauthinfo_Idx PRIMARY KEY ( Idx ASC ) );
CREATE TABLE tbl_protocolinfo( Idx INT AUTO_INCREMENT NOT NULL, dck TINYINT(1) NOT NULL, ProtocolMsgID INT NOT NULL, ProtocolID INT NOT NULL, ProtocolName VARCHAR(64) NOT NULL, ProtocolExplain VARCHAR(256) NOT NULL, ProtocolFldCnt TINYINT NOT NULL, UpdateDate DATETIME NULL, CONSTRAINT PF_tbl_protocolinfo_Idx PRIMARY KEY ( Idx ASC ) );
CREATE TABLE tbl_rfaccount( id_hmac VARBINARY(32) NOT NULL, id_enc VARBINARY(128) NOT NULL, password_hash VARCHAR(255) NOT NULL, accounttype TINYINT NOT NULL, birthdate DATETIME NOT NULL, CONSTRAINT PK_tbl_rfaccount PRIMARY KEY ( id_hmac ASC ) );
