CREATE TABLE tbl_StaffAccount( Serial INT AUTO_INCREMENT NOT NULL, ID_hmac VARBINARY(32) NOT NULL, ID_enc VARBINARY(128) NOT NULL, PW_hash VARCHAR(255) NOT NULL, Grade TINYINT NOT NULL, Depart VARCHAR(32) NOT NULL, RealName VARCHAR(12) NOT NULL, LastConnIP CHAR(16) NOT NULL, CreateDT DATETIME NOT NULL, LastLoginDT DATETIME NOT NULL, LastLogoffDT DATETIME NOT NULL, TotalLogMin INT NOT NULL, SubGrade TINYINT NOT NULL, ExpireDT DATETIME NOT NULL, ComClass VARCHAR(12) NOT NULL, BirthDay CHAR(10) NOT NULL, CONSTRAINT PK_tbl_StaffAccount PRIMARY KEY ( Serial ASC ), CONSTRAINT IX_tbl_StaffAccount UNIQUE ( ID_hmac ASC ) );
CREATE TABLE tbl_StaffAccount_BKP( Serial INT AUTO_INCREMENT NOT NULL, ID_hmac VARBINARY(32) NOT NULL, ID_enc VARBINARY(128) NOT NULL, PW_hash VARCHAR(255) NOT NULL, Grade TINYINT NOT NULL, Depart VARCHAR(32) NOT NULL, RealName VARCHAR(12) NOT NULL, LastConnIP CHAR(16) NOT NULL, CreateDT DATETIME NOT NULL, LastLoginDT DATETIME NOT NULL, LastLogoffDT DATETIME NOT NULL, TotalLogMin INT NOT NULL, SubGrade TINYINT NOT NULL, ExpireDT DATETIME NOT NULL, ComClass VARCHAR(12) NOT NULL, BirthDay CHAR(10) NOT NULL );
CREATE TABLE tbl_UserAccount( serial INT AUTO_INCREMENT NOT NULL, id_hmac VARBINARY(32) NOT NULL, id_enc VARBINARY(128) NOT NULL, createtime DATETIME NOT NULL, createip CHAR(16) NOT NULL, lastlogintime DATETIME NOT NULL, lastlogofftime DATETIME NOT NULL, totallogmin INT NOT NULL, lastconnectip CHAR(16) NOT NULL, pushclosetime DATETIME NOT NULL, pusherip CHAR(16) NOT NULL, JoinCode INT NOT NULL, LoginFailureCnt TINYINT NOT NULL, fire_on DATETIME NOT NULL, fire_warning DATETIME NOT NULL, uilock TINYINT NOT NULL, uilock_pw VARCHAR(255) NOT NULL, uilock_failcnt TINYINT NOT NULL, uilock_update DATETIME NOT NULL, uilock_hintindex TINYINT NOT NULL, uilock_hintanswer VARCHAR(255) NOT NULL, uilock_find_pass_failcnt TINYINT NOT NULL, CONSTRAINT PK_tbl_rfuser PRIMARY KEY ( id_hmac ASC ), CONSTRAINT IX_tbl_rfuser UNIQUE ( serial ASC ) );
CREATE TABLE tbl_UserBan( nAccountSerial INT NOT NULL, dtStartDate DATETIME NOT NULL, nPeriod INT NOT NULL, nKind TINYINT NOT NULL, szReason VARCHAR(32) NULL, GMReason VARCHAR(32) NOT NULL, GMWriter VARCHAR(32) NOT NULL, ReasonType TINYINT NOT NULL, CONSTRAINT PK_tbl_UserBan PRIMARY KEY ( nAccountSerial ASC ) );
CREATE TABLE tbl_UserBan_Log( nSerial INT AUTO_INCREMENT NOT NULL, nAccountSerial INT NOT NULL, dtStartdate DATETIME NOT NULL, nPeriod INT NOT NULL, nKind TINYINT NOT NULL, szReason VARCHAR(32) NULL, GMReason VARCHAR(32) NOT NULL, GMWriter VARCHAR(32) NOT NULL, CONSTRAINT PK_tbl_UserBan_Log PRIMARY KEY ( nSerial ASC ) );
CREATE TABLE tbl_UserCount_Log( serial INT AUTO_INCREMENT NOT NULL, dtDate DATETIME NOT NULL, nAverageUser INT NOT NULL, nMaxUser INT NOT NULL, nMaxUserTestServer INT NOT NULL, CONSTRAINT PK_tbl_UserCount_Log PRIMARY KEY ( serial ASC ) );
CREATE TABLE tbl_usercurrentstate( serial INT NOT NULL, state TINYINT NOT NULL, CONSTRAINT PK_tbl_usercurrentstate PRIMARY KEY ( serial ASC ) );
CREATE TABLE tbl_UserPush_Log( nAccountSerial INT NOT NULL, dtDate DATETIME NOT NULL, PushIP VARCHAR(16) NOT NULL, CloseIP VARCHAR(16) NOT NULL, CONSTRAINT PK_tbl_UserPush_Log PRIMARY KEY ( nAccountSerial ASC, dtDate ASC ) );
