CREATE TABLE tbl_WorldServer_List( Serial INT NOT NULL, Name VARCHAR(32) NOT NULL, State INT NOT NULL, LastUpdate DATETIME NOT NULL, msrepl_tran_version uniqueidentifier NOT NULL, CONSTRAINT PK_tbl_WorldServer_List PRIMARY KEY ( Serial ASC ) );
